<body>
  <main class="game-shell">
    <section class="topbar" aria-label="Game status">
      <div class="scoreboard">
        <div class="stat">
          <span class="label">Score</span>
          <span class="value" id="score">0</span>
        </div>
        <div class="stat">
          <span class="label">Best</span>
          <span class="value" id="best-score">0</span>
        </div>
      </div>
      <button class="restart-button" id="restart-top" type="button">Restart</button>
    </section>

    <section class="board-wrap">
      <canvas id="board" width="600" height="600" aria-label="Snake game board"></canvas>
      <div class="overlay visible" id="overlay" aria-live="polite">
        <div class="panel">
          <h1 id="overlay-title">Snake</h1>
          <p id="overlay-message">Use the arrow keys to move. Eat food, grow longer, and avoid walls or yourself.</p>
          <div class="final-score" id="final-score"></div>
          <button id="restart-overlay" type="button">Start Game</button>
        </div>
      </div>
    </section>

    <p class="hint">Arrow keys move the snake. Press Enter or tap restart to play again after a game over.</p>
  </main>

  <script>
    const GRID_SIZE = 20;
    const STEP_MS = 115;
    const STORAGE_KEY = "snake-best-score";

    const canvas = document.getElementById("board");
    const ctx = canvas.getContext("2d");
    const scoreEl = document.getElementById("score");
    const bestScoreEl = document.getElementById("best-score");
    const overlay = document.getElementById("overlay");
    const overlayTitle = document.getElementById("overlay-title");
    const overlayMessage = document.getElementById("overlay-message");
    const finalScoreEl = document.getElementById("final-score");
    const restartButtons = [
      document.getElementById("restart-top"),
      document.getElementById("restart-overlay")
    ];

    let snake = [];
    let direction = { x: 1, y: 0 };
    let nextDirection = { x: 1, y: 0 };
    let food = { x: 0, y: 0 };
    let score = 0;
    let bestScore = Number(localStorage.getItem(STORAGE_KEY)) || 0;
    let running = false;
    let animationFrameId = 0;
    let lastStepTime = 0;

    bestScoreEl.textContent = String(bestScore);

    function resizeCanvas() {
      const size = Math.max(320, Math.floor(canvas.getBoundingClientRect().width));
      const pixelRatio = window.devicePixelRatio || 1;
      canvas.width = Math.floor(size * pixelRatio);
      canvas.height = Math.floor(size * pixelRatio);
      ctx.setTransform(pixelRatio, 0, 0, pixelRatio, 0, 0);
      draw();
    }

    function showOverlay(title, message, buttonLabel, finalScoreText) {
      overlayTitle.textContent = title;
      overlayMessage.textContent = message;
      document.getElementById("restart-overlay").textContent = buttonLabel;
      finalScoreEl.textContent = finalScoreText || "";
      overlay.classList.add("visible");
    }

    function hideOverlay() {
      overlay.classList.remove("visible");
    }

    function randomEmptyCell() {
      const occupied = new Set(snake.map((segment) => `${segment.x},${segment.y}`));
      const emptyCells = [];

      for (let y = 0; y < GRID_SIZE; y += 1) {
        for (let x = 0; x < GRID_SIZE; x += 1) {
          const key = `${x},${y}`;
          if (!occupied.has(key)) {
            emptyCells.push({ x, y });
          }
        }
      }

      return emptyCells[Math.floor(Math.random() * emptyCells.length)] || { x: 0, y: 0 };
    }

    function spawnFood() {
      food = randomEmptyCell();
    }

    function syncScores() {
      scoreEl.textContent = String(score);
      bestScoreEl.textContent = String(bestScore);
    }

    function resetGame() {
      const center = Math.floor(GRID_SIZE / 2);
      snake = [
        { x: center - 1, y: center },
        { x: center - 2, y: center },
        { x: center - 3, y: center }
      ];
      direction = { x: 1, y: 0 };
      nextDirection = { x: 1, y: 0 };
      score = 0;
      lastStepTime = 0;
      spawnFood();
      syncScores();
      running = true;
      hideOverlay();
      cancelAnimationFrame(animationFrameId);
      animationFrameId = requestAnimationFrame(gameLoop);
      draw();
    }

    function endGame() {
      running = false;
      if (score > bestScore) {
        bestScore = score;
        localStorage.setItem(STORAGE_KEY, String(bestScore));
      }
      syncScores();
      showOverlay(
        "Game Over",
        "You hit a wall or ran into yourself.",
        "Play Again",
        `Final Score: ${score}`
      );
    }

    function setDirection(x, y) {
      if (!running) {
        return;
      }

      if (x === -direction.x && y === -direction.y) {
        return;
      }

      nextDirection = { x, y };
    }

    function update() {
      direction = nextDirection;

      const head = snake[0];
      const nextHead = {
        x: head.x + direction.x,
        y: head.y + direction.y
      };

      const outOfBounds =
        nextHead.x < 0 ||
        nextHead.x >= GRID_SIZE ||
        nextHead.y < 0 ||
        nextHead.y >= GRID_SIZE;

      const hitsSelf = snake.some((segment) => segment.x === nextHead.x && segment.y === nextHead.y);

      if (outOfBounds || hitsSelf) {
        endGame();
        return;
      }

      snake.unshift(nextHead);

      if (nextHead.x === food.x && nextHead.y === food.y) {
        score += 1;
        if (score > bestScore) {
          bestScore = score;
          localStorage.setItem(STORAGE_KEY, String(bestScore));
        }
        spawnFood();
        syncScores();
      } else {
        snake.pop();
      }
    }

    function drawGrid(cellSize, boardSize) {
      ctx.strokeStyle = "rgba(255, 255, 255, 0.06)";
      ctx.lineWidth = 1;

      for (let i = 1; i < GRID_SIZE; i += 1) {
        const offset = Math.round(i * cellSize) + 0.5;
        ctx.beginPath();
        ctx.moveTo(offset, 0);
        ctx.lineTo(offset, boardSize);
        ctx.stroke();

        ctx.beginPath();
        ctx.moveTo(0, offset);
        ctx.lineTo(boardSize, offset);
        ctx.stroke();
      }
    }

    function drawRoundedCell(x, y, cellSize, fillStyle, inset = 2) {
      const px = x * cellSize + inset;
      const py = y * cellSize + inset;
      const size = cellSize - inset * 2;
      const radius = Math.max(4, Math.floor(size * 0.2));

      ctx.fillStyle = fillStyle;
      ctx.beginPath();
      ctx.moveTo(px + radius, py);
      ctx.lineTo(px + size - radius, py);
      ctx.quadraticCurveTo(px + size, py, px + size, py + radius);
      ctx.lineTo(px + size, py + size - radius);
      ctx.quadraticCurveTo(px + size, py + size, px + size - radius, py + size);
      ctx.lineTo(px + radius, py + size);
      ctx.quadraticCurveTo(px, py + size, px, py + size - radius);
      ctx.lineTo(px, py + radius);
      ctx.quadraticCurveTo(px, py, px + radius, py);
      ctx.closePath();
      ctx.fill();
    }

    function draw() {
      const boardSize = canvas.clientWidth;
      const cellSize = boardSize / GRID_SIZE;

      ctx.clearRect(0, 0, boardSize, boardSize);

      drawGrid(cellSize, boardSize);

      drawRoundedCell(food.x, food.y, cellSize, "#ef4444", 4);

      snake.forEach((segment, index) => {
        const color = index === 0 ? "#4ade80" : "#22c55e";
        drawRoundedCell(segment.x, segment.y, cellSize, color, 3);
      });

      if (snake[0]) {
        const head = snake[0];
        const eyeOffset = cellSize * 0.22;
        const eyeSize = Math.max(2, cellSize * 0.08);
        const centerX = head.x * cellSize + cellSize / 2;
        const centerY = head.y * cellSize + cellSize / 2;
        const horizontal = direction.x !== 0;

        ctx.fillStyle = "#052e16";
        if (horizontal) {
          ctx.beginPath();
          ctx.arc(centerX + direction.x * eyeOffset, centerY - eyeOffset, eyeSize, 0, Math.PI * 2);
          ctx.arc(centerX + direction.x * eyeOffset, centerY + eyeOffset, eyeSize, 0, Math.PI * 2);
          ctx.fill();
        } else {
          ctx.beginPath();
          ctx.arc(centerX - eyeOffset, centerY + direction.y * eyeOffset, eyeSize, 0, Math.PI * 2);
          ctx.arc(centerX + eyeOffset, centerY + direction.y * eyeOffset, eyeSize, 0, Math.PI * 2);
          ctx.fill();
        }
      }
    }

    function gameLoop(timestamp) {
      if (!running) {
        draw();
        return;
      }

      if (!lastStepTime) {
        lastStepTime = timestamp;
      }

      const elapsed = timestamp - lastStepTime;
      if (elapsed >= STEP_MS) {
        lastStepTime = timestamp;
        update();
        draw();
      }

      animationFrameId = requestAnimationFrame(gameLoop);
    }

    function handleKeydown(event) {
      switch (event.key) {
        case "ArrowUp":
          event.preventDefault();
          setDirection(0, -1);
          break;
        case "ArrowDown":
          event.preventDefault();
          setDirection(0, 1);
          break;
        case "ArrowLeft":
          event.preventDefault();
          setDirection(-1, 0);
          break;
        case "ArrowRight":
          event.preventDefault();
          setDirection(1, 0);
          break;
        case "Enter":
          if (!running) {
            resetGame();
          }
          break;
        default:
          break;
      }
    }

    restartButtons.forEach((button) => {
      button.addEventListener("click", resetGame);
    });

    window.addEventListener("keydown", handleKeydown, { passive: false });
    window.addEventListener("resize", resizeCanvas);

    resizeCanvas();
    syncScores();
    showOverlay(
      "Snake",
      "Use the arrow keys to move. Eat food, grow longer, and avoid walls or yourself.",
      "Start Game"
    );
  </script>
</body>
</html>
