      running = false;
      if (score > bestScore) {
        bestScore = score;
        localStorage.setItem(STORAGE_KEY, String(bestScore));
      }
      syncScores();
      showOverlay(
        "Game Over",
        "You hit a wall or ran into yourself.",
        "Play Again",
        `Final Score: ${score}`
      );
    }

    function setDirection(x, y) {
      if (!running) {
        return;
      }

      if (x === -direction.x && y === -direction.y) {
        return;
      }

      nextDirection = { x, y };
    }

    function update() {
      direction = nextDirection;

      const head = snake[0];
      const nextHead = {
        x: head.x + direction.x,
        y: head.y + direction.y
      };

      const outOfBounds =
        nextHead.x < 0 ||
        nextHead.x >= GRID_SIZE ||
        nextHead.y < 0 ||
        nextHead.y >= GRID_SIZE;

      const hitsSelf = snake.some((segment) => segment.x === nextHead.x && segment.y === nextHead.y);

      if (outOfBounds || hitsSelf) {
        endGame();
        return;
      }

      snake.unshift(nextHead);

      if (nextHead.x === food.x && nextHead.y === food.y) {
        score += 1;
        if (score > bestScore) {
          bestScore = score;
          localStorage.setItem(STORAGE_KEY, String(bestScore));
        }
        spawnFood();
        syncScores();
      } else {
        snake.pop();
      }
    }

    function drawGrid(cellSize, boardSize) {
      ctx.strokeStyle = "rgba(255, 255, 255, 0.06)";
      ctx.lineWidth = 1;

      for (let i = 1; i < GRID_SIZE; i += 1) {
        const offset = Math.round(i * cellSize) + 0.5;
        ctx.beginPath();
        ctx.moveTo(offset, 0);
        ctx.lineTo(offset, boardSize);
        ctx.stroke();

        ctx.beginPath();
        ctx.moveTo(0, offset);
        ctx.lineTo(boardSize, offset);
        ctx.stroke();
      }
    }

    function drawRoundedCell(x, y, cellSize, fillStyle, inset = 2) {
      const px = x * cellSize + inset;
      const py = y * cellSize + inset;
      const size = cellSize - inset * 2;
      const radius = Math.max(4, Math.floor(size * 0.2));

      ctx.fillStyle = fillStyle;
      ctx.beginPath();
      ctx.moveTo(px + radius, py);
      ctx.lineTo(px + size - radius, py);
      ctx.quadraticCurveTo(px + size, py, px + size, py + radius);
      ctx.lineTo(px + size, py + size - radius);
      ctx.quadraticCurveTo(px + size, py + size, px + size - radius, py + size);
      ctx.lineTo(px + radius, py + size);
      ctx.quadraticCurveTo(px, py + size, px, py + size - radius);
      ctx.lineTo(px, py + radius);
      ctx.quadraticCurveTo(px, py, px + radius, py);
      ctx.closePath();
      ctx.fill();
    }

    function draw() {
      const boardSize = canvas.clientWidth;
      const cellSize = boardSize / GRID_SIZE;

      ctx.clearRect(0, 0, boardSize, boardSize);

      drawGrid(cellSize, boardSize);

      drawRoundedCell(food.x, food.y, cellSize, "#ef4444", 4);

      snake.forEach((segment, index) => {
        const color = index === 0 ? "#4ade80" : "#22c55e";
        drawRoundedCell(segment.x, segment.y, cellSize, color, 3);
      });

      if (snake[0]) {
        const head = snake[0];
        const eyeOffset = cellSize * 0.22;
        const eyeSize = Math.max(2, cellSize * 0.08);
        const centerX = head.x * cellSize + cellSize / 2;
        const centerY = head.y * cellSize + cellSize / 2;
        const horizontal = direction.x !== 0;

        ctx.fillStyle = "#052e16";
        if (horizontal) {
          ctx.beginPath();
          ctx.arc(centerX + direction.x * eyeOffset, centerY - eyeOffset, eyeSize, 0, Math.PI * 2);
          ctx.arc(centerX + direction.x * eyeOffset, centerY + eyeOffset, eyeSize, 0, Math.PI * 2);
          ctx.fill();
        } else {
          ctx.beginPath();
          ctx.arc(centerX - eyeOffset, centerY + direction.y * eyeOffset, eyeSize, 0, Math.PI * 2);
          ctx.arc(centerX + eyeOffset, centerY + direction.y * eyeOffset, eyeSize, 0, Math.PI * 2);
          ctx.fill();
        }
      }
    }

    function gameLoop(timestamp) {
      if (!running) {
        draw();
        return;
      }

      if (!lastStepTime) {
        lastStepTime = timestamp;
      }

      const elapsed = timestamp - lastStepTime;
      if (elapsed >= STEP_MS) {
        lastStepTime = timestamp;
        update();
        draw();
      }

      animationFrameId = requestAnimationFrame(gameLoop);
    }

    function handleKeydown(event) {
      switch (event.key) {
        case "ArrowUp":
          event.preventDefault();
          setDirection(0, -1);
          break;
        case "ArrowDown":
          event.preventDefault();
          setDirection(0, 1);
          break;
        case "ArrowLeft":
          event.preventDefault();
          setDirection(-1, 0);
          break;
        case "ArrowRight":
          event.preventDefault();
          setDirection(1, 0);
          break;
        case "Enter":
          if (!running) {
            resetGame();
          }
          break;
        default:
          break;
      }
    }

    restartButtons.forEach((button) => {
      button.addEventListener("click", resetGame);
    });

    window.addEventListener("keydown", handleKeydown, { passive: false });
    window.addEventListener("resize", resizeCanvas);

    resizeCanvas();
    syncScores();
    showOverlay(
      "Snake",
      "Use the arrow keys to move. Eat food, grow longer, and avoid walls or yourself.",
      "Start Game"
    );
  </script>
